DECLARE @s FLOAT=100;
DECLARE @ple INT=(SELECT cntr_value FROM sys.dm_os_performance_counters WHERE object_name LIKE '%Buffer Manager%' AND counter_name='Page life expectancy');
DECLARE @blk INT=(SELECT COUNT(*) FROM sys.dm_exec_requests WHERE blocking_session_id>0);
DECLARE @mg INT=(SELECT COUNT(*) FROM sys.dm_exec_query_memory_grants WHERE grant_time IS NULL);
DECLARE @ch FLOAT=(SELECT CAST(SUM(CASE WHEN usecounts>1 THEN 1 ELSE 0 END) AS FLOAT)/NULLIF(COUNT(*),0)*100 FROM sys.dm_exec_cached_plans WHERE objtype IN('Adhoc','Prepared'));
IF @ple<300 SET @s=@s-25 ELSE IF @ple<600 SET @s=@s-10;
IF @blk>0 SET @s=@s-(@blk*10);
IF @mg>0 SET @s=@s-(@mg*15);
IF @ch<80 SET @s=@s-15 ELSE IF @ch<90 SET @s=@s-5;
IF @s<0 SET @s=0;
SELECT CAST(@s AS INT) AS [Health];

SELECT status AS [Status], COUNT(*) AS [Count]
FROM sys.dm_exec_sessions WHERE is_user_process=1
GROUP BY status ORDER BY COUNT(*) DESC;

SELECT COUNT(*) AS [Databases]
FROM sys.databases
WHERE state_desc = 'ONLINE';

SELECT COUNT(session_id) AS [Connections]
FROM sys.dm_exec_sessions
WHERE is_user_process = 1;

SELECT cntr_value AS [Batch Req/s]
FROM sys.dm_os_performance_counters
WHERE counter_name = 'Batch Requests/sec';

SELECT TOP 8 ISNULL(NULLIF(program_name,''),'Unknown') AS [App], COUNT(*) AS [Sessions]
FROM sys.dm_exec_sessions WHERE is_user_process=1
GROUP BY program_name ORDER BY COUNT(*) DESC;

SELECT COUNT(*) AS [Pending Grants]
FROM sys.dm_exec_query_memory_grants
WHERE grant_time IS NULL;
